const UPLOAD_SW_VERSION = '1.0.0';
const CHANNEL_NAME = 'nextplay-uploads';
const PART_CONCURRENCY = 2;
const MAX_PART_RETRIES = 3;

importScripts('/static/js/upload-idb.js');

const IDB = self.NextPlayUploadIDB;
const channel = new BroadcastChannel(CHANNEL_NAME);

self.addEventListener('install', function(e) {
  console.log('[SW] install', UPLOAD_SW_VERSION);
  self.skipWaiting();
});

self.addEventListener('activate', function(e) {
  console.log('[SW] activate', UPLOAD_SW_VERSION);
  e.waitUntil(self.clients.claim().then(function() {
    return resumeAllJobs();
  }));
});

self.addEventListener('message', function(e) {
  var msg = e.data || {};
  if (msg.type === 'PING') {
    e.source && e.source.postMessage({ type: 'PONG', version: UPLOAD_SW_VERSION });
    return;
  }
  if (msg.type === 'ENQUEUE') {
    e.waitUntil(runJob(msg.uploadId));
    return;
  }
  if (msg.type === 'CANCEL') {
    e.waitUntil(cancelJob(msg.uploadId));
    return;
  }
  if (msg.type === 'LIST_JOBS') {
    e.waitUntil(IDB.listJobs().then(function(jobs) {
      var publicJobs = jobs.map(publicJob);
      if (e.source) e.source.postMessage({ type: 'JOBS_LIST', jobs: publicJobs });
    }));
    return;
  }
  if (msg.type === 'RESUME_ALL') {
    e.waitUntil(resumeAllJobs());
    return;
  }
});

function publicJob(job) {
  return {
    id: job.id,
    status: job.status,
    fileName: job.fileName,
    fileSize: job.fileSize,
    bytesUploaded: job.bytesUploaded || 0,
    partsDone: (job.completedParts || []).length,
    partsTotal: job.partsTotal || 0,
    error: job.error || null,
    title: (job.meta && job.meta.title) || job.fileName
  };
}

function broadcast(msg) {
  try { channel.postMessage(msg); } catch (e) { console.warn('[SW] broadcast fail', e); }
}

async function resumeAllJobs() {
  var jobs = await IDB.listJobs();
  for (var i = 0; i < jobs.length; i++) {
    var j = jobs[i];
    if (j.status === 'pending' || j.status === 'uploading' || j.status === 'finalizing' || j.status === 'registering') {
      runJob(j.id).catch(function(err) { console.error('[SW] resume fail', err); });
    }
  }
}

async function cancelJob(uploadId) {
  var job = await IDB.getJob(uploadId);
  if (!job) return;
  job.status = 'aborted';
  job.abortFlag = true;
  await IDB.putJob(job);
  broadcast({ type: 'ABORTED', uploadId: uploadId });

  await IDB.deleteJobAndBlob(uploadId);
}

async function runJob(uploadId) {
  var job = await IDB.getJob(uploadId);
  if (!job) return;
  if (job.status === 'done' || job.status === 'aborted') return;

  try {
    var blob = await IDB.getBlob(uploadId);
    if (!blob) throw new Error('Blob missing from IDB');

    if (!job.presign) {
      job.status = 'pending';
      await IDB.putJob(job);
      var presign = await apiPost('/api/scouting/s3/presign-upload', {
        file_name: job.fileName,
        file_size: job.fileSize,
        content_type: job.contentType || 'video/mp4'
      });
      job.presign = presign;
      job.partsTotal = presign.mode === 'single' ? 1 : presign.urls.length;
      job.completedParts = job.completedParts || [];
      await IDB.putJob(job);
    }

    job.status = 'uploading';
    await IDB.putJob(job);
    broadcast({ type: 'PROGRESS', uploadId: uploadId, pct: 0, partsDone: 0, partsTotal: job.partsTotal, title: job.meta.title || job.fileName });

    if (job.presign.mode === 'single') {
      await uploadSingle(job, blob);
    } else {
      await uploadMultipart(job, blob);
    }

    try {
      await fetch('/api/auth/refresh', {
        method: 'POST',
        credentials: 'include',
        headers: { 'X-Requested-With': 'XMLHttpRequest' }
      });
    } catch (e) {  }

    if (job.presign.mode === 'multipart') {
      job.status = 'finalizing';
      await IDB.putJob(job);
      await apiPost('/api/scouting/s3/complete-multipart', {
        key: job.presign.key,
        upload_id: job.presign.upload_id,
        parts: job.completedParts
      });
    }

    job.status = 'registering';
    await IDB.putJob(job);
    var m = job.meta || {};
    var reg = await apiPost('/api/scouting/videos', {
      s3_key: job.presign.key || job.singleKey,
      original_name: job.fileName,
      file_size: job.fileSize,
      title: m.title || job.fileName,
      video_type: m.type || 'game',
      custom_type_note: m.customType || null,
      opponent: m.opponent || null,
      game_date: m.gameDate || null,
      keep_forever: !!m.keepForever
    });

    job.status = 'done';
    await IDB.putJob(job);
    broadcast({ type: 'DONE', uploadId: uploadId, videoId: reg.id, title: m.title || job.fileName });
    await IDB.deleteJobAndBlob(uploadId);

  } catch (err) {
    console.error('[SW] job failed', uploadId, err);
    var failJob = await IDB.getJob(uploadId);
    if (failJob) {
      failJob.status = 'error';
      failJob.error = String(err && err.message || err);
      await IDB.putJob(failJob);
    }
    broadcast({ type: 'ERROR', uploadId: uploadId, error: String(err && err.message || err) });
  }
}

async function uploadSingle(job, blob) {
  var url = job.presign.url;
  job.singleKey = job.presign.key;
  await IDB.putJob(job);

  await putWithRetry(url, blob, job.contentType || 'video/mp4', job, 1, 1, function(loaded) {
    var pct = Math.round((loaded / job.fileSize) * 100);
    broadcast({ type: 'PROGRESS', uploadId: job.id, pct: Math.min(pct, 99), partsDone: 0, partsTotal: 1, title: job.meta.title || job.fileName });
  });

  job.completedParts = [{ part_number: 1, etag: 'single' }];
  await IDB.putJob(job);
}

async function uploadMultipart(job, blob) {
  var urls = job.presign.urls;
  var partSize = job.presign.part_size;
  var completed = new Set((job.completedParts || []).map(function(p) { return p.part_number; }));
  var partProgress = {};

  (job.completedParts || []).forEach(function(p) {
    var start = (p.part_number - 1) * partSize;
    var end = Math.min(start + partSize, job.fileSize);
    partProgress[p.part_number] = end - start;
  });

  function reportProgress() {
    var uploaded = 0;
    Object.values(partProgress).forEach(function(v) { uploaded += v; });
    var pct = Math.round((uploaded / job.fileSize) * 100);
    broadcast({
      type: 'PROGRESS',
      uploadId: job.id,
      pct: Math.min(pct, 99),
      partsDone: (job.completedParts || []).length,
      partsTotal: urls.length,
      title: job.meta.title || job.fileName
    });
  }

  var queueIndex = 0;
  async function worker() {
    while (queueIndex < urls.length) {
      var freshJob = await IDB.getJob(job.id);
      if (!freshJob || freshJob.abortFlag || freshJob.status === 'aborted') {
        throw new Error('Upload cancelled');
      }
      var idx = queueIndex++;
      var item = urls[idx];
      if (completed.has(item.part_number)) continue;

      var start = (item.part_number - 1) * partSize;
      var end = Math.min(start + partSize, blob.size);
      var chunk = blob.slice(start, end);
      partProgress[item.part_number] = 0;

      var etag = await putWithRetry(item.url, chunk, null, job, item.part_number, urls.length, function(loaded) {
        partProgress[item.part_number] = loaded;
        reportProgress();
      });

      job.completedParts.push({ part_number: item.part_number, etag: etag });
      partProgress[item.part_number] = end - start;
      await IDB.putJob(job);
      reportProgress();
    }
  }

  var workers = [];
  var n = Math.min(PART_CONCURRENCY, urls.length);
  for (var i = 0; i < n; i++) workers.push(worker());
  await Promise.all(workers);
}

async function putWithRetry(url, body, contentType, job, partNum, totalParts, onProgress) {
  var lastErr;
  for (var attempt = 0; attempt < MAX_PART_RETRIES; attempt++) {
    var freshJob = await IDB.getJob(job.id);
    if (!freshJob || freshJob.abortFlag) throw new Error('Upload cancelled');

    try {
      var headers = {};
      if (contentType) headers['Content-Type'] = contentType;
      var res = await fetchWithProgress(url, body, headers, onProgress);
      if (res.ok) {
        return res.headers.get('ETag') || 'unknown';
      }
      throw new Error('Part ' + partNum + ' failed: HTTP ' + res.status);
    } catch (e) {
      lastErr = e;
      if (String(e.message).indexOf('cancelled') >= 0) throw e;
      if (attempt === MAX_PART_RETRIES - 1) break;
      await new Promise(function(r) { setTimeout(r, 1000 * Math.pow(2, attempt)); });
    }
  }
  throw lastErr || new Error('Upload failed after retries');
}

var _streamingSupported = null;
function supportsStreamingUpload() {
  if (_streamingSupported !== null) return _streamingSupported;
  try {
    new Request('', { method: 'POST', body: new ReadableStream(), duplex: 'half' });
    _streamingSupported = true;
  } catch (e) {
    _streamingSupported = false;
  }
  return _streamingSupported;
}

async function fetchWithProgress(url, body, headers, onProgress) {
  if (supportsStreamingUpload() && body && typeof body.stream === 'function') {
    var total = body.size;
    var uploaded = 0;
    var reader = body.stream().getReader();
    var stream = new ReadableStream({
      async pull(controller) {
        try {
          var r = await reader.read();
          if (r.done) { controller.close(); return; }
          uploaded += r.value.byteLength;
          try { onProgress && onProgress(uploaded); } catch(e) {}
          controller.enqueue(r.value);
        } catch (e) { controller.error(e); }
      }
    });
    return fetch(url, {
      method: 'PUT',
      headers: headers,
      body: stream,
      duplex: 'half'
    });
  }

  try { onProgress && onProgress(0); } catch(e) {}
  var res = await fetch(url, { method: 'PUT', headers: headers, body: body });
  try { onProgress && onProgress(body.size || 0); } catch(e) {}
  return res;
}

async function apiPost(path, body) {
  var res = await fetch(path, {
    method: 'POST',
    credentials: 'include',
    headers: {
      'Content-Type': 'application/json',
      'X-Requested-With': 'XMLHttpRequest'
    },
    body: JSON.stringify(body)
  });
  var ct = res.headers.get('content-type') || '';
  if (!ct.includes('application/json')) {
    if (res.status === 401 || res.redirected) {
      throw new Error('Session expired');
    }
    throw new Error('API ' + path + ' failed: HTTP ' + res.status);
  }
  var data = await res.json();
  if (!res.ok) throw new Error(data.error || ('API ' + path + ' failed'));
  return data;
}